@namespace Lumeo

@{
    var context = new ToggleGroupContext(Type, _selectedItems, Variant, Size, EventCallback.Factory.Create<string>(this, ToggleItem));
}

<div role="group" class="@CssClass" @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        @ChildContent
    </CascadingValue>
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public ToggleGroupType Type { get; set; } = ToggleGroupType.Single;
    [Parameter] public ToggleGroupVariant Variant { get; set; } = ToggleGroupVariant.Default;
    [Parameter] public ToggleGroupSize Size { get; set; } = ToggleGroupSize.Default;
    [Parameter] public string? Value { get; set; }
    [Parameter] public EventCallback<string?> ValueChanged { get; set; }
    [Parameter] public IEnumerable<string>? SelectedValues { get; set; }
    [Parameter] public EventCallback<IEnumerable<string>> SelectedValuesChanged { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly HashSet<string> _selectedItems = new();

    private string CssClass => $"flex items-center gap-1 {Class}".Trim();

    protected override void OnParametersSet()
    {
        if (Type == ToggleGroupType.Single && Value is not null)
        {
            _selectedItems.Clear();
            _selectedItems.Add(Value);
        }
        else if (Type == ToggleGroupType.Multiple && SelectedValues is not null)
        {
            _selectedItems.Clear();
            foreach (var v in SelectedValues) _selectedItems.Add(v);
        }
    }

    private async Task ToggleItem(string value)
    {
        if (_selectedItems.Contains(value))
        {
            _selectedItems.Remove(value);
        }
        else
        {
            if (Type == ToggleGroupType.Single)
            {
                _selectedItems.Clear();
            }
            _selectedItems.Add(value);
        }
        StateHasChanged();

        if (Type == ToggleGroupType.Single)
            await ValueChanged.InvokeAsync(_selectedItems.FirstOrDefault());
        else
            await SelectedValuesChanged.InvokeAsync(_selectedItems.ToList());
    }

    public enum ToggleGroupType { Single, Multiple }
    public enum ToggleGroupVariant { Default, Outline }
    public enum ToggleGroupSize { Default, Sm, Lg }

    public record ToggleGroupContext(ToggleGroupType Type, HashSet<string> SelectedItems, ToggleGroupVariant Variant, ToggleGroupSize Size, EventCallback<string> Toggle)
    {
        public bool IsSelected(string value) => SelectedItems.Contains(value);
    }
}

@namespace Lumeo
@inject Lumeo.Services.IComponentInteropService Interop

<button @ref="_el" type="button" aria-pressed="@IsPressed.ToString().ToLower()" class="@CssClass" @onclick="Toggle" disabled="@Disabled" @attributes="AdditionalAttributes">
    @ChildContent
</button>

@code {
    [Parameter, EditorRequired] public string Value { get; set; } = "";
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Disabled { get; set; }

    /// <summary>
    /// Visual feedback when the item is pressed. Default is
    /// <see cref="Button.ButtonPressEffect.None"/>.
    /// </summary>
    [Parameter] public Button.ButtonPressEffect PressEffect { get; set; } = Button.ButtonPressEffect.None;

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    [CascadingParameter] public ToggleGroup.ToggleGroupContext Context { get; set; } = default!;

    private Microsoft.AspNetCore.Components.ElementReference _el;

    private bool IsPressed => Context.SelectedItems.Contains(Value);

    private string CssClass => string.Join(" ", new[] { VariantClasses, SizeClasses, BaseClasses, "cursor-pointer disabled:cursor-not-allowed", PressEffectClass, Class }.Where(s => !string.IsNullOrWhiteSpace(s)));

    // gap-1.5 mirrors Button's base gap so icon+label children space cleanly without
    // requiring consumers to add Class="gap-1.5" manually. Single-child renders are
    // unaffected (gap only matters when there are multiple flex children).
    private const string BaseClasses = "inline-flex items-center justify-center gap-1.5 rounded-md text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50";

    private string? PressEffectClass => PressEffect switch
    {
        Button.ButtonPressEffect.Scale => "lumeo-press-scale",
        Button.ButtonPressEffect.Brightness => "lumeo-press-brightness",
        Button.ButtonPressEffect.Ripple => "lumeo-press-ripple",
        _ => null
    };

    private string VariantClasses => (Context.Variant, IsPressed) switch
    {
        (ToggleGroup.ToggleGroupVariant.Default, true) => "bg-accent text-accent-foreground",
        (ToggleGroup.ToggleGroupVariant.Default, false) => "bg-transparent hover:bg-muted hover:text-muted-foreground",
        (ToggleGroup.ToggleGroupVariant.Outline, true) => "bg-accent text-accent-foreground border border-input",
        (ToggleGroup.ToggleGroupVariant.Outline, false) => "border border-input bg-transparent hover:bg-accent hover:text-accent-foreground",
        _ => ""
    };

    private string SizeClasses => Context.Size switch
    {
        ToggleGroup.ToggleGroupSize.Default => "h-9 px-3",
        ToggleGroup.ToggleGroupSize.Sm => "h-8 px-2",
        ToggleGroup.ToggleGroupSize.Lg => "h-10 px-4",
        _ => ""
    };

    private async Task Toggle()
    {
        if (!Disabled)
        {
            await Context.Toggle.InvokeAsync(Value);
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender && PressEffect == Button.ButtonPressEffect.Ripple)
        {
            try
            {
                await Interop.RippleAttachAsync(_el);
            }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }
    }
}
